import{_ as t,o as a,c as s,g as e}from"./chunks/framework.CtuiYkcd.js";const $=JSON.parse('{"title":"二五八","description":"","frontmatter":{"title":"二五八","date":"2023-08-15T00:30:35.142Z","length":"250字","time":"1分钟","aside":false,"hash":629900989},"headers":[],"relativePath":"idea/258.md","filePath":"idea/258.md"}'),o={name:"idea/258.md"},n=e("p",null,"爱情是建立在两个独立人格平等的相互选择之上的。",-1),c=e("p",null,"这是爱情的理想状态。由于爱情的私密和排他性，我们往往认为爱情是两个人的事，但事实上它是社会性的：因为独立、平等的确定和保证，相互选择的尺度和标准都是在某个具体的社会条件下决定的。那么当我们询问世界上是否存在爱情时，我们应该先问这个社会是否为爱情准备了足够的条件，然后再问当这样或那样的条件缺失时，一个个人能够并愿意付出多少代价来维系这种存在。当我们无视爱情的社会性，我们必然会得出种种片面而武断的“人性”结论。",-1),d=e("p",null,"当我们考察一切社会关系时，都可以发展类似的思考。爱情不过是我们熟悉而又陌生的典型。",-1),i=[n,c,d];function _(r,l,p,h,m,f){return a(),s("div",null,i)}const g=t(o,[["render",_]]);export{$ as __pageData,g as default};
